lue="<?= (int)($item['timeout'] ?? 8) ?>"></div><div><label><input type="checkbox" name="hasValidity" value="1" data-validity-toggle <?= !empty($item['hasValidity']) ? 'checked' : '' ?>> Gültigkeit aktiv</label></div><div class="validityFields" data-validity-fields><div><label>Gültig von</label><input type="date" name="validFrom" value="<?= h((string)($item['validFrom'] ?? date('Y-m-d'))) ?>"></div><div><label>Gültig bis</label><input type="date" name="validUntil" value="<?= h((string)($item['validUntil'] ?? date('Y-m-d', strtotime('+10 years')))) ?>"></div></div></div><div class="formActions"><button type="submit">Änderungen speichern</button></div></form></td></tr><?php endforeach; ?></tbody></table></div>
<script>
function toggleEdit(id){const row=document.getElementById(id);if(!row)return;row.style.display=row.style.display==='table-row'?'none':'table-row';}
async function loadLiveStatus(){const target=document.getElementById('liveStatus');const summary=document.getElementById('liveStatusSummary');const snapshot=document.getElementById('liveStatusSnapshot');if(!target||!summary||!snapshot)return;try{const response=await fetch('status.php',{cache:'no-store'});const data=await response.json();if(!data||data.ok!==true){target.textContent='Live-Status konnte nicht geladen werden.';summary.textContent='keine Zusammenfassung verfügbar';snapshot.textContent='kein Snapshot';return;}target.textContent='Player: '+(data.player_running?'läuft':'steht')+' | Apache: '+(data.apache_running?'läuft':'steht')+' | Aktivierte Folien: '+data.enabled_slides+' | Angeforderte Ansicht: '+(data.requested_view||'index')+' | Letzte Aktion: '+(data.last_action||'none');summary.textContent=data.status_summary||'keine Zusammenfassung vorhanden';snapshot.textContent=data.last_status_snapshot_time||'noch kein Snapshot';}catch(error){target.textContent='Live-Status konnte nicht geladen werden.';summary.textContent='keine Zusammenfassung verfügbar';snapshot.textContent='kein Snapshot';}}
function bindColorFields(){document.querySelectorAll('.colorField').forEach((field)=>{const text=field.querySelector('[data-color-text]');const picker=field.querySelector('[data-color-picker]');if(!text||!picker)return;const normalize=(value)=>{const trimmed=String(value||'').trim();return /^#[0-9a-fA-F]{6}$/.test(trimmed)?trimmed:null;};const syncFromText=()=>{const normalized=normalize(text.value);if(normalized)picker.value=normalized;};const syncFromPicker=()=>{text.value=picker.value;};text.addEventListener('input',syncFromText);picker.addEventListener('input',syncFromPicker);syncFromText();});}
function bindConfirmForms(){document.querySelectorAll('.confirmForm').forEach((form)=>{form.addEventListener('submit',(event)=>{const message=form.getAttribute('data-confirm')||'Wirklich ausführen?';if(!window.confirm(message))event.preventDefault();});});}
function bindValidityFields(){document.querySelectorAll('form').forEach((form)=>{const toggle=form.querySelector('[data-validity-toggle]');const fields=form.querySelector('[data-validity-fields]');if(!toggle||!fields)return;const update=()=>{fields.style.display=toggle.checked?'contents':'none';};toggle.addEventListener('change',update);update();});}
loadLiveStatus();bindColorFields();bindConfirmForms();bindValidityFields();setInterval(loadLiveStatus,15000);
</script></body></html>
